class Solution:
    def wordPattern(self, pattern, s):
        words = s.split()
        if len(words) != len(pattern):
            return False
        # Independent check: a valid bijection means zipping the two sequences
        # yields a set of pairs with as many distinct letters and distinct
        # words as there are distinct pairs.
        pairs = set(zip(pattern, words))
        return len(pairs) == len(set(pattern)) == len(set(words))

