class Solution:
    def wordPattern(self, pattern, s):
        words = s.split()
        if len(words) != len(pattern):
            return False
        l2w = {}
        w2l = {}
        for c, w in zip(pattern, words):
            if c in l2w and l2w[c] != w:
                return False
            if w in w2l and w2l[w] != c:
                return False
            l2w[c] = w
            w2l[w] = c
        return True

