var wordPattern = function(pattern, s) {
    const words = s.split(' ');
    if (words.length !== pattern.length) return false;
    const l2w = new Map();
    const w2l = new Map();
    for (let i = 0; i < pattern.length; i++) {
        const c = pattern[i], w = words[i];
        if (l2w.has(c) && l2w.get(c) !== w) return false;
        if (w2l.has(w) && w2l.get(w) !== c) return false;
        l2w.set(c, w);
        w2l.set(w, c);
    }
    return true;
};
